// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  AircraftMaintenanceHistory v3
 * @notice FAA-Compliant Maintenance Record Ledger — BNB Testnet
 *
 * @dev    Implements the "automated gatekeeper" described in the paper:
 *         Submissions are programmatically rejected if they fail to satisfy:
 *           1. Valid 14 CFR Part 65 mechanic license reference (non-empty, min length)
 *           2. Non-null cryptographic Content Identifier (rawCid, processedCid)
 *           3. Unique File ID mapping (no duplicate rawCid on-chain)
 *           4. Timestamp verification (block.timestamp must be > 0, future timestamps rejected)
 */
contract AircraftMaintenanceHistory {

    // ─────────────────────────────────────────────
    // Constants
    // ─────────────────────────────────────────────

    // 14 CFR Part 65 mechanic certificate numbers follow format: e.g. "A&P-123456"
    // We enforce a minimum length of 6 characters as a basic schema constraint.
    uint256 public constant MIN_LICENSE_LENGTH = 6;

    // IPFS CIDv1 base32 strings are 59 chars; CIDv0 (Qm...) are 46 chars minimum.
    uint256 public constant MIN_CID_LENGTH = 46;

    // Tail numbers: FAA format is 1–5 alphanumeric chars after "N", e.g. "N550MHA"
    uint256 public constant MIN_TAIL_LENGTH = 3;

    // ─────────────────────────────────────────────
    // Admin
    // ─────────────────────────────────────────────

    mapping(address => bool) public isAdmin;

    modifier onlyAdmin() {
        require(isAdmin[msg.sender], "Only admin can call this function");
        _;
    }

    // ─────────────────────────────────────────────
    // Data Structure
    // ─────────────────────────────────────────────

    struct AircraftRecord {
        uint256 fileId;
        string  tailNumber;       // FAA tail number, e.g. "N550MHA"
        string  aircraftType;     // e.g. "B737"
        string  rawCid;           // IPFS CID — original FAA maintenance log
        string  processedCid;     // IPFS CID — processed valuation CSV
        string  mechanicLicense;  // 14 CFR Part 65 license reference
        uint256 initialPrice;     // Aircraft value in USD
        uint256 submittedAt;      // block.timestamp at submission
        address submitter;        // submitting wallet
        bool    faaValidated;     // gatekeeper passed flag
    }

    // ─────────────────────────────────────────────
    // Storage
    // ─────────────────────────────────────────────

    uint256 private _fileIdCounter;

    // fileId → record
    mapping(uint256 => AircraftRecord) private _records;

    // ─── Indexes ───
    mapping(string  => uint256[]) private _tailIndex;       // tailNumber  → fileId[]
    mapping(string  => uint256[]) private _typeIndex;       // aircraftType → fileId[]
    mapping(address => uint256[]) private _submitterIndex;  // address     → fileId[]

    // ─── Uniqueness guard (14 CFR constraint: no duplicate raw logs) ───
    // rawCid → fileId that registered it first (0 = not registered)
    mapping(string => uint256) private _cidRegistry;

    // ─────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────

    event RecordAnchored(
        uint256 indexed fileId,
        string          tailNumber,
        string          aircraftType,
        string          rawCid,
        string          processedCid,
        string          mechanicLicense,
        uint256         initialPrice,
        address indexed submitter,
        uint256         submittedAt
    );

    event RecordRejected(
        address indexed submitter,
        string          reason,
        uint256         timestamp
    );

    event AdminAdded(address indexed admin);
    event AdminRemoved(address indexed admin);

    // ─────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────

    constructor(address[] memory _admins) {
        require(_admins.length > 0, "At least one admin required");
        for (uint256 i = 0; i < _admins.length; i++) {
            require(_admins[i] != address(0), "Zero address not allowed");
            isAdmin[_admins[i]] = true;
            emit AdminAdded(_admins[i]);
        }
    }

    // ─────────────────────────────────────────────
    // Admin Management
    // ─────────────────────────────────────────────

    function addAdmin(address _admin) external onlyAdmin {
        require(_admin != address(0), "Zero address not allowed");
        require(!isAdmin[_admin], "Already an admin");
        isAdmin[_admin] = true;
        emit AdminAdded(_admin);
    }

    function removeAdmin(address _admin) external onlyAdmin {
        require(isAdmin[_admin], "Not an admin");
        require(_admin != msg.sender, "Cannot remove yourself");
        isAdmin[_admin] = false;
        emit AdminRemoved(_admin);
    }

    // ─────────────────────────────────────────────
    // GATEKEEPER — Internal FAA Schema Validation
    // ─────────────────────────────────────────────

    /**
     * @dev Validates all 14 CFR / schema constraints before anchoring.
     *      Emits RecordRejected and reverts on any failure.
     *
     *      Constraints checked:
     *        [1] mechanicLicense  — non-empty, >= MIN_LICENSE_LENGTH chars
     *        [2] rawCid           — non-empty, >= MIN_CID_LENGTH chars (non-null CID)
     *        [3] processedCid     — non-empty, >= MIN_CID_LENGTH chars
     *        [4] rawCid uniqueness — not already registered (unique File ID mapping)
     *        [5] timestamp        — block.timestamp > 0 and not a future spoof
     *        [6] tailNumber       — non-empty, >= MIN_TAIL_LENGTH
     *        [7] initialPrice     — must be > 0
     */
    function _faaGatekeeperCheck(
        string memory _tail,
        string memory _type,
        string memory _rawCid,
        string memory _processedCid,
        string memory _license,
        uint256       _price
    ) internal {

        // [1] 14 CFR Part 65 mechanic license reference
        if (bytes(_license).length < MIN_LICENSE_LENGTH) {
            emit RecordRejected(msg.sender, "REJECTED: Invalid mechanic license reference (14 CFR Part 65)", block.timestamp);
            revert("REJECTED: Invalid mechanic license reference (14 CFR Part 65)");
        }

        // [2] Non-null rawCid
        if (bytes(_rawCid).length < MIN_CID_LENGTH) {
            emit RecordRejected(msg.sender, "REJECTED: Raw CID is null or malformed", block.timestamp);
            revert("REJECTED: Raw CID is null or malformed");
        }

        // [3] Non-null processedCid
        if (bytes(_processedCid).length < MIN_CID_LENGTH) {
            emit RecordRejected(msg.sender, "REJECTED: Processed CID is null or malformed", block.timestamp);
            revert("REJECTED: Processed CID is null or malformed");
        }

        // [4] Unique File ID mapping — rawCid must not already exist on-chain
        if (_cidRegistry[_rawCid] != 0) {
            emit RecordRejected(msg.sender, "REJECTED: Duplicate CID - record already anchored", block.timestamp);
            revert("REJECTED: Duplicate CID - record already anchored");
        }

        // [5] Timestamp verification — block.timestamp is always > 0 in EVM,
        //     but we check for suspiciously future timestamps (> 10 years from now)
        //     as an additional guard against timestamp manipulation.
        require(block.timestamp > 0, "REJECTED: Timestamp verification failed");
        require(block.timestamp < 9999999999, "REJECTED: Timestamp out of valid range");

        // [6] Tail number schema
        if (bytes(_tail).length < MIN_TAIL_LENGTH) {
            emit RecordRejected(msg.sender, "REJECTED: Tail number does not meet FAA format requirements", block.timestamp);
            revert("REJECTED: Tail number does not meet FAA format requirements");
        }

        // [7] Price sanity
        if (_price == 0) {
            emit RecordRejected(msg.sender, "REJECTED: Initial price must be greater than zero", block.timestamp);
            revert("REJECTED: Initial price must be greater than zero");
        }

        // [8] Aircraft type must be provided
        if (bytes(_type).length == 0) {
            emit RecordRejected(msg.sender, "REJECTED: Aircraft type is required", block.timestamp);
            revert("REJECTED: Aircraft type is required");
        }
    }

    // ─────────────────────────────────────────────
    // Write — Anchor Record (with gatekeeper)
    // ─────────────────────────────────────────────

    /**
     * @notice Anchor a new FAA maintenance record on-chain.
     *         The gatekeeper will reject submissions that fail schema constraints.
     *
     * @param _tailNumber      FAA aircraft tail number (e.g. "N550MHA")
     * @param _aircraftType    Aircraft model (e.g. "B737")
     * @param _rawCid          IPFS CID of the original maintenance log CSV
     * @param _processedCid    IPFS CID of the processed valuation CSV
     * @param _mechanicLicense 14 CFR Part 65 mechanic license reference
     * @param _initialPrice    Aircraft initial price in USD
     * @return newFileId       Auto-incremented on-chain record ID
     */
    function addRecord(
        string memory _tailNumber,
        string memory _aircraftType,
        string memory _rawCid,
        string memory _processedCid,
        string memory _mechanicLicense,
        uint256       _initialPrice
    ) external onlyAdmin returns (uint256 newFileId) {

        // ── GATEKEEPER ──────────────────────────────
        _faaGatekeeperCheck(
            _tailNumber, _aircraftType,
            _rawCid, _processedCid,
            _mechanicLicense, _initialPrice
        );
        // ────────────────────────────────────────────

        _fileIdCounter++;
        newFileId = _fileIdCounter;

        _records[newFileId] = AircraftRecord({
            fileId:          newFileId,
            tailNumber:      _tailNumber,
            aircraftType:    _aircraftType,
            rawCid:          _rawCid,
            processedCid:    _processedCid,
            mechanicLicense: _mechanicLicense,
            initialPrice:    _initialPrice,
            submittedAt:     block.timestamp,
            submitter:       msg.sender,
            faaValidated:    true          // gatekeeper passed
        });

        // Register CID to prevent duplicates
        _cidRegistry[_rawCid] = newFileId;

        // Update search indexes
        _tailIndex[_tailNumber].push(newFileId);
        _typeIndex[_aircraftType].push(newFileId);
        _submitterIndex[msg.sender].push(newFileId);

        emit RecordAnchored(
            newFileId, _tailNumber, _aircraftType,
            _rawCid, _processedCid, _mechanicLicense,
            _initialPrice, msg.sender, block.timestamp
        );
    }

    // ─────────────────────────────────────────────
    // Read — by fileId
    // ─────────────────────────────────────────────

    function getRecord(uint256 _fileId)
        external view returns (AircraftRecord memory)
    {
        require(_records[_fileId].fileId != 0, "Record does not exist");
        return _records[_fileId];
    }

    function totalRecords() external view returns (uint256) {
        return _fileIdCounter;
    }

    // ─────────────────────────────────────────────
    // Read — by Tail Number
    // ─────────────────────────────────────────────

    function getFileIdsByTail(string memory _tail)
        external view returns (uint256[] memory)
    {
        return _tailIndex[_tail];
    }

    function getRecordsByTail(string memory _tail)
        external view returns (AircraftRecord[] memory)
    {
        uint256[] memory ids = _tailIndex[_tail];
        AircraftRecord[] memory result = new AircraftRecord[](ids.length);
        for (uint256 i = 0; i < ids.length; i++) {
            result[i] = _records[ids[i]];
        }
        return result;
    }

    function getLatestRecordByTail(string memory _tail)
        external view returns (AircraftRecord memory)
    {
        uint256[] memory ids = _tailIndex[_tail];
        require(ids.length > 0, "No records found for this tail number");
        return _records[ids[ids.length - 1]];
    }

    // ─────────────────────────────────────────────
    // Read — by Type / Submitter
    // ─────────────────────────────────────────────

    function getFileIdsByType(string memory _type)
        external view returns (uint256[] memory)
    {
        return _typeIndex[_type];
    }

    function getFileIdsBySubmitter(address _addr)
        external view returns (uint256[] memory)
    {
        return _submitterIndex[_addr];
    }

    // ─────────────────────────────────────────────
    // Read — CID Uniqueness Check (callable from frontend)
    // ─────────────────────────────────────────────

    /**
     * @notice Returns the fileId that registered a given CID (0 = not yet registered).
     *         Frontend can call this before submission to give early feedback.
     */
    function getCidRegistry(string memory _rawCid)
        external view returns (uint256)
    {
        return _cidRegistry[_rawCid];
    }
}

